package search

import "sort"

// Registry holds every registered search field, keyed by name.
type Registry struct {
	fields map[string]Field
}

// Lookup returns the Field for the given name, or false if unknown.
func (r *Registry) Lookup(name string) (Field, bool) {
	f, ok := r.fields[name]
	return f, ok
}

// All returns every registered field in an unspecified order.
func (r *Registry) All() []Field {
	out := make([]Field, 0, len(r.fields))
	for _, f := range r.fields {
		out = append(out, f)
	}
	return out
}

// Descriptors returns metadata for every registered field. This is the
// contract consumed by the future GET /api/search/fields handler.
func (r *Registry) Descriptors() []FieldDescriptor {
	out := make([]FieldDescriptor, 0, len(r.fields))
	for _, f := range r.fields {
		out = append(out, f.Descriptor())
	}
	return out
}

// OutputDescriptors returns metadata for fields that appear in search result
// columns (OutputDefault != nil). The caller decides how to order them.
func (r *Registry) OutputDescriptors() []FieldDescriptor {
	out := make([]FieldDescriptor, 0, len(r.fields))
	for _, f := range r.fields {
		d := f.Descriptor()
		if d.OutputDefault != nil {
			out = append(out, d)
		}
	}
	return out
}

// ExportableDescriptors returns metadata for fields that are exportable and
// have an output representation. Results are ordered by theme (AllThemes order)
// then by registration order within each theme.
func (r *Registry) ExportableDescriptors() []FieldDescriptor {
	// Build theme-index map for sorting.
	themeIndex := make(map[Theme]int, len(AllThemes))
	for i, t := range AllThemes {
		themeIndex[t] = i
	}

	// Collect qualifying fields preserving registration order.
	type indexedDesc struct {
		regOrder int
		desc     FieldDescriptor
	}
	var items []indexedDesc
	for i, f := range allFields() {
		d := f.Descriptor()
		if d.Exportable != nil && *d.Exportable && d.OutputDefault != nil {
			items = append(items, indexedDesc{regOrder: i, desc: d})
		}
	}

	// Sort by theme order, stable within theme (registration order).
	sort.SliceStable(items, func(i, j int) bool {
		ti := themeIndex[items[i].desc.Theme]
		tj := themeIndex[items[j].desc.Theme]
		if ti != tj {
			return ti < tj
		}
		return items[i].regOrder < items[j].regOrder
	})

	out := make([]FieldDescriptor, len(items))
	for i, item := range items {
		out[i] = item.desc
	}
	return out
}

// NewRegistry constructs and returns a fully populated Registry.
func NewRegistry() *Registry {
	r := &Registry{fields: make(map[string]Field)}
	for _, f := range allFields() {
		r.fields[f.Name()] = f
	}
	return r
}

// allFields returns the complete list of search fields.
// Every field must set visibility, searchability, and exportable explicitly — no defaults.
func allFields() []Field {
