package resolver

import (
	"context"
	"testing"

	"github.com/ketang/kapow/api/graph/model"
	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/search"
)

// authContext returns a context with dummy JWT claims (authenticated user).
func authContext() context.Context {
	return auth.SetClaims(context.Background(), &auth.Claims{Email: "test@example.com"})
}

// findFieldByName searches the returned slice for the field with the given name.
func findFieldByName(t *testing.T, fields []model.SearchField, name string) model.SearchField {
	t.Helper()
	for _, f := range fields {
		switch v := f.(type) {
		case *model.TextSearchField:
			if v.Name == name {
				return f
			}
		case *model.BinarySearchField:
			if v.Name == name {
				return f
			}
		case *model.ChoiceSearchField:
			if v.Name == name {
				return f
			}
		case *model.NumericalSearchField:
			if v.Name == name {
				return f
			}
		case *model.NumericalRangeSearchField:
			if v.Name == name {
				return f
			}
		case *model.GeoSearchField:
			if v.Name == name {
				return f
			}
		}
	}
	t.Fatalf("findFieldByName: field %q not found in %d results", name, len(fields))
	return nil
}

func newTestSearchFieldsResolver() *queryResolver {
	return &queryResolver{
		Resolver: &Resolver{
			Search: search.NewRegistry(),
		},
	}
}

// TestSearchFields_ReturnsAllVisibleFields verifies the count matches visible
// descriptors (excludes HIDDEN fields which are never returned).
func TestSearchFields_ReturnsAllVisibleFields(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	r := newTestSearchFieldsResolver()

	// Use authenticated context to include RESTRICTED fields.
	fields, err := r.SearchFields(authContext())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	// Count non-HIDDEN descriptors — HIDDEN fields are never returned.
	want := 0
	for _, d := range reg.Descriptors() {
		if d.Visibility != search.VisibilityHidden {
			want++
		}
	}
	if len(fields) != want {
		t.Errorf("len(fields) = %d, want %d (visible descriptors)", len(fields), want)
	}
}

// TestSearchFields_BinaryDetection verifies online_only maps to BinarySearchField.
func TestSearchFields_BinaryDetection(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "online_only")
	if _, ok := f.(*model.BinarySearchField); !ok {
		t.Errorf("online_only: got %T, want *model.BinarySearchField", f)
	}
}

// TestSearchFields_GenderChoice verifies gender maps to ChoiceSearchField with 3 options.
func TestSearchFields_GenderChoice(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "gender")
	cf, ok := f.(*model.ChoiceSearchField)
	if !ok {
		t.Fatalf("gender: got %T, want *model.ChoiceSearchField", f)
	}
	if len(cf.Options) != 3 {
		t.Errorf("gender options count: got %d, want 3", len(cf.Options))
	}
	if cf.MaxSelections == nil || *cf.MaxSelections != 1 {
		t.Errorf("gender MaxSelections: got %v, want ptr(1)", cf.MaxSelections)
	}
}

// TestSearchFields_StateMultiSelect verifies state maps to ChoiceSearchField with
// unlimited MaxSelections (nil) and 50 options.
func TestSearchFields_StateMultiSelect(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "state")
	cf, ok := f.(*model.ChoiceSearchField)
	if !ok {
		t.Fatalf("state: got %T, want *model.ChoiceSearchField", f)
	}
	if cf.MaxSelections != nil {
		t.Errorf("state MaxSelections: got %v, want nil (unlimited multi-select)", cf.MaxSelections)
	}
	if len(cf.Options) != 50 {
		t.Errorf("state options count: got %d, want 50", len(cf.Options))
	}
}

// TestSearchFields_NumericalRange_Units verifies admission_rate maps to
// NumericalRangeSearchField with unit PERCENTAGE.
func TestSearchFields_NumericalRange_Units(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "admission_rate")
	nrf, ok := f.(*model.NumericalRangeSearchField)
	if !ok {
		t.Fatalf("admission_rate: got %T, want *model.NumericalRangeSearchField", f)
	}
	if nrf.Unit == nil || *nrf.Unit != model.SearchFieldUnitPercentage {
		t.Errorf("admission_rate Unit: got %v, want PERCENTAGE", nrf.Unit)
	}
	// Bounds should be set to 0.0–1.0
	if nrf.Min == nil || *nrf.Min != 0.0 {
		t.Errorf("admission_rate Min: got %v, want 0.0", nrf.Min)
	}
	if nrf.Max == nil || *nrf.Max != 1.0 {
		t.Errorf("admission_rate Max: got %v, want 1.0", nrf.Max)
	}
}

// TestSearchFields_TextMaxLength verifies the name field maps to TextSearchField
// with MaxLength=512.
func TestSearchFields_TextMaxLength(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "name")
	tf, ok := f.(*model.TextSearchField)
	if !ok {
		t.Fatalf("name: got %T, want *model.TextSearchField", f)
	}
	if tf.MaxLength == nil || *tf.MaxLength != 512 {
		t.Errorf("name MaxLength: got %v, want ptr(512)", tf.MaxLength)
	}
}

// TestSearchFields_GeoField verifies the location field maps to GeoSearchField
// with a positive maxRadiusMiles derived from the registry's MaxRadiusKm.
func TestSearchFields_GeoField(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "location")
	gf, ok := f.(*model.GeoSearchField)
	if !ok {
		t.Fatalf("location: got %T, want *model.GeoSearchField", f)
	}
	// 500 km × 0.621371 ≈ 310.7 miles
	if gf.MaxRadiusMiles <= 0 {
		t.Errorf("location MaxRadiusMiles: got %f, want > 0", gf.MaxRadiusMiles)
	}
}

// TestSearchFields_DefaultVisibilitySearchability verifies that ordinary fields
// default to VISIBLE + SEARCHABLE.
func TestSearchFields_DefaultVisibilitySearchability(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	// "name" should be VISIBLE + SEARCHABLE (the default for most fields).
	f := findFieldByName(t, fields, "name")
	tf, ok := f.(*model.TextSearchField)
	if !ok {
		t.Fatalf("name: got %T, want *model.TextSearchField", f)
	}
	if tf.Visibility != search.VisibilityVisible {
		t.Errorf("name Visibility: got %v, want VISIBLE", tf.Visibility)
	}
	if tf.Searchability != search.SearchabilitySearchable {
		t.Errorf("name Searchability: got %v, want SEARCHABLE", tf.Searchability)
	}
}

// TestSearchFields_HiddenExcluded verifies that HIDDEN fields (e.g. unit_id)
// are never returned by SearchFields, even for authenticated users.
func TestSearchFields_HiddenExcluded(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	// Even authenticated context should not see HIDDEN fields.
	fields, err := r.SearchFields(authContext())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	for _, f := range fields {
		var name string
		switch v := f.(type) {
		case *model.TextSearchField:
			name = v.Name
		case *model.BinarySearchField:
			name = v.Name
		case *model.ChoiceSearchField:
			name = v.Name
		case *model.NumericalSearchField:
			name = v.Name
		case *model.NumericalRangeSearchField:
			name = v.Name
		case *model.GeoSearchField:
			name = v.Name
		}
		if name == "unit_id" {
			t.Error("HIDDEN field unit_id should not appear in SearchFields results")
		}
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// SearchOutputFields resolver tests
// ─────────────────────────────────────────────────────────────────────────────

// TestSearchOutputFields_ReturnsSubset verifies that SearchOutputFields returns
// fewer items than SearchFields (some fields are input-only).
func TestSearchOutputFields_ReturnsSubset(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	allFields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields error: %v", err)
	}
	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	if len(outFields) == 0 {
		t.Fatal("SearchOutputFields returned empty slice")
	}
	if len(outFields) >= len(allFields) {
		t.Errorf("output fields count %d >= all fields count %d; some should be input-only",
			len(outFields), len(allFields))
	}
}

// TestSearchOutputFields_DefaultVisibleFields verifies that known default-visible
// fields (name, city, state, enrollment, institution_type) are present and marked
// defaultVisible=true.
func TestSearchOutputFields_DefaultVisibleFields(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	// Index by name for easy lookup.
	byName := make(map[string]*model.SearchOutputField, len(outFields))
	for _, f := range outFields {
		byName[f.Name] = f
	}

	for _, name := range []string{"name", "city", "state", "enrollment", "institution_type"} {
		f, ok := byName[name]
		if !ok {
			t.Errorf("field %q missing from SearchOutputFields", name)
			continue
		}
		if !f.DefaultVisible {
			t.Errorf("field %q: DefaultVisible = false, want true", name)
		}
	}
}

// TestSearchOutputFields_InputOnlyExcluded verifies that input-only fields
// (location, carnegie_basic, congressional_district, fields_of_study) are absent.
func TestSearchOutputFields_InputOnlyExcluded(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	byName := make(map[string]bool, len(outFields))
	for _, f := range outFields {
		byName[f.Name] = true
	}

	for _, name := range []string{"location", "carnegie_basic", "congressional_district", "fields_of_study"} {
		if byName[name] {
			t.Errorf("input-only field %q should not appear in SearchOutputFields", name)
		}
	}
}

// TestSearchOutputFields_SortableFields verifies that numeric fields like
// enrollment and admission_rate are sortable, while enum fields like state are not.
func TestSearchOutputFields_SortableFields(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	byName := make(map[string]*model.SearchOutputField, len(outFields))
	for _, f := range outFields {
		byName[f.Name] = f
	}

	sortable := []string{"enrollment", "admission_rate", "tuition_in_state", "rank_us_news_national"}
	for _, name := range sortable {
		f, ok := byName[name]
		if !ok {
			t.Errorf("field %q missing from output fields", name)
			continue
		}
		if !f.Sortable {
			t.Errorf("field %q: Sortable = false, want true", name)
		}
	}

	notSortable := []string{"institution_type", "ncaa_division", "application_platforms"}
	for _, name := range notSortable {
		f, ok := byName[name]
		if !ok {
			t.Errorf("field %q missing from output fields", name)
			continue
		}
		if f.Sortable {
			t.Errorf("field %q: Sortable = true, want false", name)
		}
	}
}

// TestSearchOutputFields_UnitPropagated verifies that currency/percentage units
// propagate to SearchOutputField.Unit.
func TestSearchOutputFields_UnitPropagated(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	byName := make(map[string]*model.SearchOutputField, len(outFields))
	for _, f := range outFields {
		byName[f.Name] = f
	}

	// tuition_in_state → DOLLARS
	if f, ok := byName["tuition_in_state"]; ok {
		if f.Unit == nil || *f.Unit != model.SearchFieldUnitDollars {
			t.Errorf("tuition_in_state: Unit = %v, want DOLLARS", f.Unit)
		}
	} else {
		t.Error("tuition_in_state missing from output fields")
	}

	// admission_rate → PERCENTAGE (0.0–1.0 bounds)
	if f, ok := byName["admission_rate"]; ok {
		if f.Unit == nil || *f.Unit != model.SearchFieldUnitPercentage {
			t.Errorf("admission_rate: Unit = %v, want PERCENTAGE", f.Unit)
		}
	} else {
		t.Error("admission_rate missing from output fields")
	}
}

// TestSearchOutputFields_SharedMetadata verifies that name/label/visibility/exportable
// match their counterparts in SearchFields for a representative field.
func TestSearchOutputFields_SharedMetadata(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	allFields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields error: %v", err)
	}
	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	// Find "enrollment" in both slices.
	inputEnrollment := findFieldByName(t, allFields, "enrollment")
	nrf, ok := inputEnrollment.(*model.NumericalRangeSearchField)
	if !ok {
		t.Fatalf("enrollment in SearchFields: got %T, want NumericalRangeSearchField", inputEnrollment)
	}

	var outputEnrollment *model.SearchOutputField
	for _, f := range outFields {
		if f.Name == "enrollment" {
			outputEnrollment = f
			break
		}
	}
	if outputEnrollment == nil {
		t.Fatal("enrollment missing from SearchOutputFields")
	}

	// Shared metadata must match.
	if outputEnrollment.Label != nrf.Label {
		t.Errorf("enrollment label mismatch: input=%q output=%q", nrf.Label, outputEnrollment.Label)
	}
	if outputEnrollment.Visibility != nrf.Visibility {
		t.Errorf("enrollment visibility mismatch: input=%v output=%v", nrf.Visibility, outputEnrollment.Visibility)
	}
	if outputEnrollment.Exportable != nrf.Exportable {
		t.Errorf("enrollment exportable mismatch: input=%v output=%v", nrf.Exportable, outputEnrollment.Exportable)
	}
}

// TestSearchFields_AnonExcludesHidden verifies that anonymous context excludes
// HIDDEN fields, resulting in fewer fields than the full descriptor list.
func TestSearchFields_AnonExcludesHidden(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	r := newTestSearchFieldsResolver()

	anonFields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields (anon) returned error: %v", err)
	}
	authFields, err := r.SearchFields(authContext())
	if err != nil {
		t.Fatalf("SearchFields (auth) returned error: %v", err)
	}

	// Both should exclude HIDDEN; since there are no RESTRICTED fields in the
	// current registry, anon and auth counts should be equal.
	hiddenCount := 0
	for _, d := range reg.Descriptors() {
		if d.Visibility == search.VisibilityHidden {
			hiddenCount++
		}
	}
	if hiddenCount == 0 {
		t.Fatal("expected at least one HIDDEN field in the registry")
	}

	allCount := len(reg.Descriptors())
	if len(anonFields) != allCount-hiddenCount {
		t.Errorf("anon field count = %d, want %d (all %d - hidden %d)",
			len(anonFields), allCount-hiddenCount, allCount, hiddenCount)
	}
	if len(authFields) != allCount-hiddenCount {
		t.Errorf("auth field count = %d, want %d", len(authFields), allCount-hiddenCount)
	}
}

// TestSearchOutputFields_MultiEnum verifies a multi-enum field has no MaxSelections cap.
func TestSearchFields_MultiEnum(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	// application_platforms is a multi-enum field in the registry
	f := findFieldByName(t, fields, "application_platforms")
	cf, ok := f.(*model.ChoiceSearchField)
	if !ok {
		t.Fatalf("application_platforms: got %T, want *model.ChoiceSearchField", f)
	}
	if cf.MaxSelections != nil {
		t.Errorf("application_platforms MaxSelections: got %v, want nil (unlimited)", cf.MaxSelections)
	}
}

